import numpy as npimport pandas as pdimport matplotlib.pyplot as pltimport seaborn as sns# Настройка отображения DataFramepd.set_option('display.max_columns', None)pd.set_option('display.width', None)pd.set_option('display.max_colwidth', 50)# Загрузка данныхxle = pd.read_csv('personages_complete.csv')# Вывод таблицыprint("Таблица по характеристикам:")print(xle.head())print(f"\nОбщее количество: {len(xle)}")# Подготовка данных для визуализацииstats_columns = ['hp', 'attack', 'defense', 'sp_attack', 'sp_defense', 'speed']stats_data = xle[stats_columns]stats_data_melted = stats_data.melt(var_name='Stat', value_name='Value')# # Создание графикаplt.figure(figsize=(12, 8))# seaborm указаывает на датафрейм из которго берутся значения и устанавливает обозначенияsns.boxplot(data=stats_data_melted, x='Stat', y='Value', palette='viridis')plt.title('Распределение основных характеристик', fontsize=16)plt.xlabel('Характеристика', fontsize=12)plt.ylabel('Значение', fontsize=12)# Установить метки на оси X (и повернуть их)plt.xticks(rotation=45)# настраивает отступы между элементами графикаplt.tight_layout()plt.show()